SELECT year, region, sector, source_type, SUM(total) AS total_energy_consumption
FROM energy_consumption
GROUP BY year, region, sector, source_type;

SELECT year, month, region, sector, economic_growth_rate, technological_advancement_score, regulatory_change_impact
FROM energy_analysis
ORDER BY economic_growth_rate DESC, technological_advancement_score DESC, regulatory_change_impact DESC;

SELECT region
FROM energy_consumption
WHERE year = '2020' AND total > 100;

SELECT consumption_trend, production_trend
FROM energy_analysis
WHERE year = '1' AND month = '1' AND region = '1' AND sector = '1';

SELECT region
FROM energy_analysis
WHERE year = '2020' AND consumption_trend = 'increase';
